select *
from energy_account_balance_consume_record
where consume_time >= #{query.beginTime}
  and consume_time < #{query.endTime}
  and consume_type = #{monthlyConsumeType}
  and account_id in

    #{accountId}

  and is_deleted = 0
order by account_id asc, consume_time asc, id asc

select distinct account_id
from energy_account_order_flow
where create_time >= #{beginTime}
  and create_time < #{endTime}

select distinct account_id from energy_account_cancel_record where create_time < #{beginTime} and full_cancel = true and account_id in
#{accountId}
and is_deleted = 0

select *
from energy_account_order_flow
where create_time >= #{query.beginTime}
  and create_time < #{query.endTime}
  and balance_type = #{balanceType}
  and account_id in

    #{accountId}

order by account_id asc, create_time asc, id asc

select * from energy_account_open_record where account_id in
#{accountId}
and is_deleted = 0 order by account_id asc
